// Pull both ensures' `forall |lo, hi|` quantifiers into the proof context
// with explicit triggers on `post*_self_.gap(lo, hi)`. The two original
// ensures clauses have disjoint triggers (one fires on post1's gap, the
// other on post2's), so z3 never lines them up — re-asserting them keeps
// the same definitional content but gives us a clean handle to derive the
// joint pointwise equality below.
assert(forall |lo: KeyIterator<K>, hi: KeyIterator<K>|
    #[trigger] post1_self_.gap(lo, hi) <==>
        pre_self_.gap(lo, hi)
        && !(lo.lt_spec(KeyIterator::new_spec(k))
            && KeyIterator::new_spec(k).lt_spec(hi)));
assert(forall |lo: KeyIterator<K>, hi: KeyIterator<K>|
    #[trigger] post2_self_.gap(lo, hi) <==>
        pre_self_.gap(lo, hi)
        && !(lo.lt_spec(KeyIterator::new_spec(k))
            && KeyIterator::new_spec(k).lt_spec(hi)));

// Both views equal the same `pre_self_@.insert(k, v)`, so they're equal
// by transitivity. Pull both equalities in explicitly and then conclude.
assert(post1_self_@ == pre_self_@.insert(k, v));
assert(post2_self_@ == pre_self_@.insert(k, v));
assert(post1_self_@ == post2_self_@);

// Pointwise gap equality: both `gap` predicates have, at every (lo, hi),
// the *same* RHS, so they agree pointwise. The two triggers
// `post1_self_.gap(lo, hi)` and `post2_self_.gap(lo, hi)` give z3 two
// independent handles to instantiate this joint forall whenever either
// `gap` appears in the obligation, which is exactly what closes the
// determinism check.
assert(forall |lo: KeyIterator<K>, hi: KeyIterator<K>|
    #[trigger] post1_self_.gap(lo, hi) <==> #[trigger] post2_self_.gap(lo, hi));
